// Helper methods on ShardInner
impl<K: Clone, V: Clone> ShardInner<K, V> {
    fn update_recency(&mut self, node_idx: usize) {
        // Move node to head (most recent)
        if let Some(node) = &self.nodes[node_idx] {
            let prev = node.prev;
            let next = node.next;
            // Remove from current position
            if let Some(prev_idx) = prev {
                if let Some(ref mut pnode) = self.nodes[prev_idx] {
                    pnode.next = next;
                }
            } else {
                self.head = next;
            }
            if let Some(next_idx) = next {
                if let Some(ref mut nnode) = self.nodes[next_idx] {
                    nnode.prev = prev;
                }
            } else {
                self.tail = prev;
            }
            // Insert at head
            if let Some(ref mut node) = self.nodes[node_idx] {
                node.prev = None;
                node.next = self.head;
            }
            if let Some(head_idx) = self.head {
                if let Some(ref mut hnode) = self.nodes[head_idx] {
                    hnode.prev = Some(node_idx);
                }
            }
            self.head = Some(node_idx);
            if self.tail.is_none() {
                self.tail = Some(node_idx);
            }
        }
    }

    fn put(&mut self, key: K, value: V, capacity: usize) -> Option<V> {
        if let Some(&node_idx) = self.map.get(&key) {
            // Key exists, update value and move to head
            if let Some(ref mut node) = self.nodes[node_idx] {
                let old = std::mem::replace(&mut node.value, value);
                self.update_recency(node_idx);
                return Some(old);
            }
        } else {
            // New key
            if self.len >= capacity {
                // Evict LRU (tail)
                if let Some(tail_idx) = self.tail {
                    if let Some(tail_node) = self.nodes[tail_idx].take() {
                        self.map.remove(&tail_node.key);
                        self.free.push(tail_idx);
                        // Remove from list
                        let prev = tail_node.prev;
                        if let Some(prev_idx) = prev {
                            if let Some(ref mut pnode) = self.nodes[prev_idx] {
                                pnode.next = None;
                            }
                        } else {
                            self.head = None;
                        }
                        self.tail = prev;
                        self.len -= 1;
                    }
                }
            }
            // Insert new node
            let node_idx = if let Some(free_idx) = self.free.pop() {
                free_idx
            } else {
                let new_idx = self.nodes.len();
                self.nodes.push(None);
                new_idx
            };
